using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ────────────────────────────────────────────────────────────────
    // CalculateTotal – DataRow (inline compile-time data)
    // ────────────────────────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_ValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ────────────────────────────────────────────────────────────────
    // CalculateTotal – DynamicData (runtime-generated edge cases)
    // ────────────────────────────────────────────────────────────────

    public static IEnumerable<object[]> CalculateTotal_InvalidInputs
    {
        get
        {
            yield return new object[] { -1m, 1, 0.1m, "unitPrice", "Negative unit price" };
            yield return new object[] { 10m, -1, 0.1m, "quantity", "Negative quantity" };
            yield return new object[] { 10m, 1, -0.01m, "taxRate", "Tax rate below zero" };
            yield return new object[] { 10m, 1, 1.01m, "taxRate", "Tax rate above 1" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(CalculateTotal_InvalidInputs), DynamicDataSourceType.Property)]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRangeException(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParamName, string scenario)
    {
        var ex = Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName, $"Failed for scenario: {scenario}");
    }

    // ────────────────────────────────────────────────────────────────
    // ApplyDiscount – DataRow
    // ────────────────────────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount (free)")]
    [DataRow(49.99, 25.0, 37.4925, DisplayName = "Fractional result")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price, any discount")]
    public void ApplyDiscount_ValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ────────────────────────────────────────────────────────────────
    // ApplyDiscount – DynamicData from method (boundary / invalid)
    // ────────────────────────────────────────────────────────────────

    public static IEnumerable<object[]> ApplyDiscount_InvalidDiscounts()
    {
        yield return new object[] { 100m, -0.01m, "Discount just below 0%" };
        yield return new object[] { 100m, -50m, "Large negative discount" };
        yield return new object[] { 100m, 100.01m, "Discount just above 100%" };
        yield return new object[] { 100m, 200m, "Discount way over 100%" };
    }

    [TestMethod]
    [DynamicData(nameof(ApplyDiscount_InvalidDiscounts), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRangeException(
        decimal price, decimal discountPercent, string scenario)
    {
        var ex = Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName, $"Failed for scenario: {scenario}");
    }
}

